from collections import defaultdict
from typing import List

class Solution:
    def maxSum(self, nums: List[int], m: int, k: int) -> int:
        n = len(nums)
        if k > n:
            return 0

        freq = defaultdict(int)
        unique_count = 0
        max_sum = 0
        current_sum = 0

        # Initialize the first window
        for i in range(k):
            current_sum += nums[i]
            freq[nums[i]] += 1
            if freq[nums[i]] == 1:
                unique_count += 1

        if unique_count >= m:
            max_sum = current_sum

        # Slide the window
        for i in range(k, n):
            outgoing = nums[i - k]
            incoming = nums[i]

            current_sum += incoming - outgoing

            freq[outgoing] -= 1
            if freq[outgoing] == 0:
                unique_count -= 1
            freq[incoming] += 1
            if freq[incoming] == 1:
                unique_count += 1

            if unique_count >= m:
                max_sum = max(max_sum, current_sum)

        return max_sum
